const express = require('express');
const bodyParser = require('body-parser');
const crypto = require('crypto');
const twilio = require('twilio');

const app = express();
app.use(bodyParser.json());

// Twilio credentials and client setup
const accountSid = 'your_account_sid';
const authToken = 'your_auth_token';
const twilioPhoneNumber = 'your_twilio_phone_number';
const client = new twilio(accountSid, authToken);

// In-memory storage for SMS codes with session IDs
const smsCodes = {};

app.post('/send-sms', (req, res) => {
  const { phoneNumber } = req.body;
  
  if (!phoneNumber) {
    return res.status(400).json({ error: 'Phone number is required' });
  }

  // Generate a random 6-digit code
  const smsCode = crypto.randomInt(100000, 999999);
  smsCodes[phoneNumber] = { code: smsCode, timestamp: Date.now() };

  // Send SMS using Twilio
  client.messages.create({
    body: `Your verification code is ${smsCode}`,
    from: twilioPhoneNumber,
    to: phoneNumber
  })
  .then(message => {
    res.status(200).json({ message: 'SMS sent successfully' });
  })
  .catch(error => {
    res.status(500).json({ error: 'Failed to send SMS', details: error.message });
  });
});

app.post('/verify-sms', (req, res) => {
  const { phoneNumber, code } = req.body;
  
  if (!phoneNumber || !code) {
    return res.status(400).json({ error: 'Phone number and code are required' });
  }

  // Check if the code exists and is valid
  if (smsCodes[phoneNumber] && smsCodes[phoneNumber].code === parseInt(code, 10)) {
    const currentTime = Date.now();
    const timeDifference = currentTime - smsCodes[phoneNumber].timestamp;

    // Allow verification for 5 minutes
    if (timeDifference <= 300000) {
      delete smsCodes[phoneNumber];
      res.status(200).json({ message: 'Code verified successfully' });
    } else {
      res.status(401).json({ error: 'Code expired' });
    }
  } else {
    res.status(401).json({ error: 'Invalid code' });
  }
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});